// Extract email data from Gmail IMAP node
const emailData = $input.item.json;

// Debug: log the raw email structure
console.log('Raw email data:', JSON.stringify(emailData, null, 2));

// Convert email date to ISO format for PostgreSQL
let receivedDate;
try {
  receivedDate = emailData.date ? new Date(emailData.date).toISOString() : new Date().toISOString();
} catch (e) {
  receivedDate = new Date().toISOString();
}

// Extract sender info - try multiple possible structures
let senderEmail = 'unknown@unknown.com';
let senderName = '';

if (emailData.from) {
  if (typeof emailData.from === 'string') {
    // Format: "Name <email@example.com>" or just "email@example.com"
    const match = emailData.from.match(/(.+?)\s*<(.+?)>/);
    if (match) {
      senderName = match[1].trim();
      senderEmail = match[2].trim();
    } else {
      senderEmail = emailData.from.trim();
    }
  } else if (emailData.from.address) {
    senderEmail = emailData.from.address;
    senderName = emailData.from.name || '';
  } else if (emailData.from.value && emailData.from.value[0]) {
    senderEmail = emailData.from.value[0].address || senderEmail;
    senderName = emailData.from.value[0].name || '';
  }
}

// Extract email body - try multiple content types
let emailContent = '';
if (emailData.text) {
  emailContent = emailData.text;
} else if (emailData.textAsHtml) {
  emailContent = emailData.textAsHtml;
} else if (emailData.html) {
  // Strip HTML tags for plain text
  emailContent = emailData.html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
} else if (emailData.body) {
  emailContent = emailData.body;
}

console.log('Extracted - Email:', senderEmail, 'Name:', senderName, 'Content length:', emailContent.length);

return {
  json: {
    sender_email: senderEmail,
    sender_name: senderName,
    subject: emailData.subject || 'No Subject',
    email_content: emailContent,
    received_date: receivedDate,
    has_attachments: (emailData.attachments && emailData.attachments.length > 0) ? 'yes' : 'no',
    attachment_count: emailData.attachments?.length || 0
  }
};

// Parse AI response and clean up JSON
const aiResponse = $input.item.json.generated_text;
const emailData = $('Extract Email Data').item.json;

// Try to extract JSON from response
let extractedData;
try {
  // Remove markdown code blocks if present
  let cleanJson = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Try to find JSON object in the response
  const jsonMatch = cleanJson.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    cleanJson = jsonMatch[0];
  }

  extractedData = JSON.parse(cleanJson);

  // Clean up currency format if present
  if (extractedData.cost_amount) {
    // Remove currency symbols and convert to number
    const costStr = String(extractedData.cost_amount).replace(/[€$£,]/g, '').trim();
    extractedData.cost_amount = parseFloat(costStr) || null;
  }

  // Ensure priority and action_required have valid values
  if (!extractedData.priority || extractedData.priority.trim() === '') {
    extractedData.priority = 'medium';
  }
  if (!extractedData.action_required || extractedData.action_required.trim() === '') {
    extractedData.action_required = 'no';
  }

} catch (error) {
  // Fallback if JSON parsing fails
  extractedData = {
    sender_name: emailData.sender_name || "Unknown",
    email_type: "other",
    topic: emailData.subject?.substring(0, 50) || "Parse Error",
    summary: aiResponse.substring(0, 200),
    date_deadline: null,
    cost_amount: null,
    currency: null,
    phone_number: null,
    priority: "medium",
    action_required: "no",
    additional_info: "AI response could not be parsed as JSON",
    parse_error: true
  };
}

// Combine with original email data
const result = {
  ...extractedData,
  sender_email: emailData.sender_email,
  subject: emailData.subject,
  original_email: emailData.email_content,
  received_at: emailData.received_date,
  has_attachments: emailData.has_attachments,
  attachment_count: emailData.attachment_count,
  processed_by: "mistral-7b",
  processed_at: new Date().toISOString()
};

return { json: result };

